import React, { useState } from "react";

import {
  Cloud,
  Sprout,
  ShoppingBag,
  Building2,
  Map,
  FileBarChart,
  TrendingUp,
  TrendingDown,
  Phone,
  Send,
  User,
  Calendar,
  Newspaper,
  ArrowRight,
  ChevronRight
} from "lucide-react";

import "./Dashboard.css";



/* ===========================
   MARKET PRICES
=========================== */

const marketPrices = [

{
icon:"🌾",

name:"Rice",

price:"₹2800 / Quintal",

change:"+2.5%",

up:true
},

{
icon:"🍅",

name:"Tomato",

price:"₹32 / Kg",

change:"-1.2%",

up:false
},

{
icon:"🧅",

name:"Onion",

price:"₹28 / Kg",

change:"-0.8%",

up:false
},

{
icon:"🌿",

name:"Cotton",

price:"₹7600 / Quintal",

change:"+1.5%",

up:true
}

];



/* ===========================
   WEATHER FORECAST
=========================== */

const forecast = [

{
day:"Today",

icon:"⛅",

temp:"31°C",

rain:"20%"
},

{
day:"Tomorrow",

icon:"🌧️",

temp:"30°C",

rain:"40%"
},

{
day:"Monday",

icon:"☀️",

temp:"33°C",

rain:"10%"
},

{
day:"Tuesday",

icon:"☀️",

temp:"34°C",

rain:"0%"
},

{
day:"Wednesday",

icon:"🌦️",

temp:"29°C",

rain:"50%"
},

{
day:"Thursday",

icon:"☁️",

temp:"30°C",

rain:"25%"
},

{
day:"Friday",

icon:"☀️",

temp:"34°C",

rain:"0%"
}

];



/* ===========================
   GOVERNMENT SCHEMES
=========================== */

const schemes = [

{
icon:"👨‍🌾",

name:"PM Kisan Samman Nidhi",

desc:"Direct income support"
},

{
icon:"🛡️",

name:"PM Fasal Bima Yojana",

desc:"Crop Insurance"
},

{
icon:"💧",

name:"PM Krishi Sinchai",

desc:"Irrigation Support"
},

{
icon:"💳",

name:"Kisan Credit Card",

desc:"Easy Farmer Loans"
}

];



/* ===========================
   QUICK ACTIONS
=========================== */

const quickActions = [

{
icon:Cloud,

label:"Weather"
},

{
icon:Sprout,

label:"Crop Advisor"
},

{
icon:ShoppingBag,

label:"Market Prices"
},

{
icon:Building2,

label:"Government Schemes"
},

{
icon:FileBarChart,

label:"Reports"
},

{
icon:Map,

label:"Maps"
}

];



/* ===========================
   INSIGHTS
=========================== */

const insights = [

{
emoji:"🌧️",

text:"Rain Tomorrow"
},

{
emoji:"🌾",

text:"Rice Season Started"
},

{
emoji:"💰",

text:"Cotton +3%"
},

{
emoji:"🏛️",

text:"PM Kisan Open"
}

];



/* ===========================
   CROPS
=========================== */

const crops = [

{
icon:"🌾",

name:"Rice",

profit:"High Yield"
},

{
icon:"🌽",

name:"Maize",

profit:"Good Demand"
},

{
icon:"🍅",

name:"Tomato",

profit:"Fast Growth"
},

{
icon:"🌿",

name:"Cotton",

profit:"High Profit"
}

];



/* ===========================
   NEWS
=========================== */

const news = [

"🌧️ Heavy rain expected this week",

"🏛️ PM Kisan installment released",

"💰 Cotton prices increased"

];



/* ===========================
   TASKS
=========================== */

const tasks = [

"✅ Water Crops",

"✅ Check Soil Moisture",

"⬜ Buy Fertilizer",

"⬜ Spray Pesticides"

];



/* ===========================
   DASHBOARD
=========================== */

export default function Dashboard({

setActivePage

}){

const [chatInput,setChatInput]=useState("");

const [chatMessages,setChatMessages]=useState([]);

function handleSend(){

if(!chatInput.trim())

return;

let reply="";

const q=chatInput.toLowerCase();

if(q.includes("rice")){

reply="Rice needs NPK fertilizer.";

}

else if(q.includes("cotton")){

reply="Cotton grows well in warm weather.";

}

else if(q.includes("rain")){

reply="Tomorrow rain probability is 40%.";

}

else if(q.includes("fertilizer")){

reply="Organic fertilizer is recommended.";

}

else{

reply="Please ask another farming question.";

}

setChatMessages(prev=>[

...prev,

{
text:chatInput,

user:true
},

{
text:reply,

user:false
}

]);

setChatInput("");

}
return(

<div className="dashboard-layout">

{/* ==========================
   LEFT SIDE
========================== */}

<div className="dashboard-main">

{/* ==========================
   HERO BANNER
========================== */}

<div className="hero-banner">

<div className="hero-overlay">

<div className="hero-badge">

🤖 AI Powered Digital Agriculture

</div>

<h1 className="hero-title">

Empowering Every Farmer Digitally 🌾

</h1>

<p className="hero-sub">

Weather • Market Prices • AI Assistant • Government Schemes • Smart Farming

</p>

<div className="hero-actions">

<button

className="btn-primary"

onClick={()=>

setActivePage(

"Weather"

)

}

>

🌦️ Check Weather

</button>

<button

className="btn-secondary"

onClick={()=>

setActivePage(

"Government Schemes"

)

}

>

🏛️ Explore Schemes

</button>

</div>

</div>

<div className="hero-image-overlay"></div>

</div>



{/* ==========================
   STATISTICS CARDS
========================== */}

<div className="stats-row">

<div className="stat-card">

<div className="stat-icon">

🌤️

</div>

<div>

<div className="stat-label">

Weather

</div>

<div className="stat-value blue">

31°C

</div>

<div className="stat-sub">

Partly Cloudy

</div>

</div>

</div>



<div className="stat-card">

<div className="stat-icon">

🌾

</div>

<div>

<div className="stat-label">

Recommended Crop

</div>

<div className="stat-value green">

Rice

</div>

<div className="stat-sub">

High Yield

</div>

</div>

</div>



<div className="stat-card">

<div className="stat-icon">

💰

</div>

<div>

<div className="stat-label">

Market Price

</div>

<div className="stat-value green">

₹2800

</div>

<div className="stat-sub">

Rice Price

</div>

</div>

</div>



<div className="stat-card">

<div className="stat-icon">

🏛️

</div>

<div>

<div className="stat-label">

Government Schemes

</div>

<div className="stat-value purple">

4 Active

</div>

<div className="stat-sub">

Available

</div>

</div>

</div>

</div>
{/* ==========================
   QUICK ACTIONS
========================== */}

<div className="card">

<div className="card-header">

<h2>

⚡ Quick Actions

</h2>

</div>

<div className="quick-actions-grid">

{quickActions.map(

({icon:Icon,label})=>(

<button

key={label}

className="quick-action-btn"

onClick={()=>

setActivePage(label)

}

>

<Icon size={30}/>

<span>

{label}

</span>

</button>

)

)}

</div>

</div>



{/* ==========================
   WEATHER FORECAST
========================== */}

<div className="card">

<div className="card-header">

<h2>

🌦️ Weather Forecast

</h2>

<button

className="view-all"

onClick={()=>

setActivePage(

"Weather"

)

}

>

View All

<ChevronRight

size={16}

/>

</button>

</div>

{forecast.map(

(item)=>(

<div

key={item.day}

className="market-row"

>

<div>

{item.day}

</div>

<div>

{item.icon}

</div>

<div>

{item.temp}

</div>

<div>

💧 {item.rain}

</div>

</div>

)

)}

</div>



{/* ==========================
   MARKET PRICES
========================== */}

<div className="card">

<div className="card-header">

<h2>

📈 Market Prices

</h2>

<button

className="view-all"

onClick={()=>

setActivePage(

"Market Prices"

)

}

>

View All

<ChevronRight

size={16}

/>

</button>

</div>

{marketPrices.map(

(item)=>(

<div

key={item.name}

className="market-row"

>

<div>

{item.icon}

</div>

<div>

{item.name}

</div>

<div>

{item.price}

</div>

<div>

{item.up ?

<TrendingUp

size={16}

/>

:

<TrendingDown

size={16}

/>

}

{" "}

{item.change}

</div>

</div>

)

)}

</div>
{/* ==========================
   GOVERNMENT SCHEMES
========================== */}

<div className="card">

<div className="card-header">

<h2>

🏛️ Government Schemes

</h2>

<button

className="view-all"

onClick={()=>

setActivePage(

"Government Schemes"

)

}

>

View All

<ChevronRight size={16}/>

</button>

</div>

{schemes.map(item=>(

<div

key={item.name}

className="market-row"

>

<div>

{item.icon}

</div>

<div style={{flex:1}}>

<h4>

{item.name}

</h4>

<p>

{item.desc}

</p>

</div>

<button

className="btn-primary"

onClick={()=>

setActivePage(

"Government Schemes"

)

}

>

Apply

<ArrowRight size={14}/>

</button>

</div>

))}

</div>



{/* ==========================
   TODAY'S FARM INSIGHTS
========================== */}

<div className="card">

<div className="card-header">

<h2>

🔥 Today's Farm Insights

</h2>

</div>

<div className="insights-grid">

{insights.map(

(item,index)=>(

<div

key={index}

className="insight-box"

>

<div

style={{

fontSize:"40px"

}}

>

{item.emoji}

</div>

<p>

{item.text}

</p>

</div>

)

)}

</div>

</div>



{/* ==========================
   RECOMMENDED CROPS
========================== */}

<div className="card">

<div className="card-header">

<h2>

🌱 Recommended Crops

</h2>

</div>

<div className="crop-grid">

{crops.map(crop=>(

<div

key={crop.name}

className="crop-card"

>

<div

style={{

fontSize:"42px"

}}

>

{crop.icon}

</div>

<h3>

{crop.name}

</h3>

<p>

{crop.profit}

</p>

<button

className="btn-primary"

onClick={()=>

setActivePage(

"Crop Advisor"

)

}

>

View Crop

</button>

</div>

))}

</div>

</div>
{/* ==========================
   AGRICULTURE NEWS
========================== */}

<div className="card">

<div className="card-header">

<h2>

📰 Agriculture News

</h2>

<button

className="view-all"

onClick={()=>

setActivePage(

"News"

)

}

>

View All

<ChevronRight size={16}/>

</button>

</div>

{news.map(

(item,index)=>(

<div

key={index}

className="news-item"

>

{item}

</div>

)

)}

</div>



{/* ==========================
   TODAY TASKS
========================== */}

<div className="card">

<div className="card-header">

<h2>

📅 Today's Tasks

</h2>

</div>

{tasks.map(

(task,index)=>(

<div

key={index}

className="task-item"

>

{task}

</div>

)

)}

</div>



</div>



{/* ==========================
   RIGHT PANEL
========================== */}

<div className="right-panel">



{/* AI ASSISTANT */}

<div className="panel-card">

<h3>

🤖 AI Assistant

</h3>

<div className="chat-messages">

{chatMessages.map(

(msg,index)=>(

<div

key={index}

className={`chat-msg ${

msg.user

?

"user-msg"

:

"bot-msg"

}`}

>

{msg.text}

</div>

)

)}

</div>

<div className="ai-input-row">

<input

type="text"

placeholder="Ask farming question"

value={chatInput}

onChange={(e)=>

setChatInput(

e.target.value

)

}

onKeyDown={(e)=>

e.key==="Enter"

&& handleSend()

}

/>

<button

className="send-btn"

onClick={handleSend}

>

<Send size={18}/>

</button>

</div>

</div>



{/* FARMER PROFILE */}

<div className="panel-card">

<h3>

👨‍🌾 Farmer Profile

</h3>

<div className="profile-box">

<div className="profile-avatar">

👨‍🌾

</div>

<h4>

Bhargavi

</h4>

<p>

West Godavari

</p>

<p>

Andhra Pradesh

</p>

<button

className="btn-primary"

onClick={()=>

setActivePage(

"Profile"

)

}

>

View Profile

</button>

</div>

</div>



{/* EMERGENCY SUPPORT */}

<div className="panel-card">

<h3>

☎️ Emergency Support

</h3>

<p>

24/7 Agriculture Helpline

</p>

<h2>

1800-180-1551

